import React, { useState } from 'react';

const App = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [mode, setMode] = useState(false);
  const [category, setCategory] = useState('Blog');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="flex items-center gap-4 w-[60%]">
        <input type="text" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} placeholder="Search" className="p-2 border-2 border-gray-500 rounded-lg"/>
        <button className="bg-[#C06C88] p-2 rounded-lg" onClick={() => setMode(!mode)}>Toggle Mode</button>
        <button className="bg-[#C06C88] p-2 rounded-lg" onClick={() => setCategory(category === 'Blog' ? 'News' : 'Blog')}>{category}</button>
      </div>
    </div>
  );
};

export default App;
